var FileBadge = class {
  constructor(container, fileName, onRemove) {
    this.container = container;
    this.fileName = fileName;
    this.onRemove = onRemove;
  }
  /**
   * 배지 렌더링
   */
  render() {
    if (!this.fileName) {
      this.clear();
      return;
    }
    this.clear();
    const badge = document.createElement("div");
    badge.className = "file-badge";
    badge.style.cssText = `
      display: inline-flex;
      align-items: center;
      gap: 8px;
      padding: 4px 12px;
      background-color: rgb(76, 175, 80);
      color: white;
      border-radius: 4px;
      font-size: 12px;
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
    `;
    const fileNameSpan = document.createElement("span");
    fileNameSpan.textContent = this.fileName;
    badge.appendChild(fileNameSpan);
    const closeButton = document.createElement("button");
    closeButton.className = "file-badge-close";
    closeButton.innerHTML = "\xD7";
    closeButton.style.cssText = `
      background: none;
      border: none;
      color: white;
      cursor: pointer;
      font-size: 14px;
      padding: 0 4px;
      line-height: 1;
    `;
    if (this.onRemove) {
      closeButton.addEventListener("click", (e) => {
        e.stopPropagation();
        this.onRemove();
      });
    }
    badge.appendChild(closeButton);
    this.container.appendChild(badge);
  }
  /**
   * 파일 변경
   */
  setFile(fileName) {
    this.fileName = fileName;
    this.render();
  }
  /**
   * 배지 제거
   */
  clear() {
    const existingBadge = this.container.querySelector(".file-badge");
    if (existingBadge) {
      existingBadge.remove();
    }
  }
};

